const fallbackEntry: BundleVisualizationEntry = {
  examplePath: 'www/src/views/IndexView/IndexLineChart.tsx',
  totalSize: fallbackTree.value,
  totalSizeLabel: '9.50 KB',
  moduleCount: 7,
  generatedAt: 'placeholder',
  stages: fallbackStages,
  tree: fallbackTree,
};
